import os from "node:os";
import { getOrCreateInstallId } from "./config.js";
/**
 * Builds the `x-bitfab-client-*` identity headers sent on every request from
 * a Bitfab plugin to the Bitfab server. Used by both the MCP transport
 * (`McpProxy`) and one-shot HTTP calls (e.g. `runTrackSkill`) so the server
 * sees a consistent client identity regardless of which channel was used.
 *
 * Does not include transport headers (Authorization, Content-Type, Accept) —
 * use {@link buildBitfabRequestHeaders} for the canonical POST header set,
 * or call this directly when you need only the identity portion.
 */
export function buildBitfabClientHeaders(pluginVersion, platform) {
    const resolvedOptions = Intl.DateTimeFormat().resolvedOptions();
    return {
        "x-bitfab-client-name": platform.cliBinary,
        "x-bitfab-client-display-name": platform.displayName,
        "x-bitfab-client-version": pluginVersion,
        "x-bitfab-client-timezone": resolvedOptions.timeZone,
        "x-bitfab-client-locale": resolvedOptions.locale,
        "x-bitfab-client-os": os.platform(),
        "x-bitfab-client-arch": os.arch(),
        "x-bitfab-client-node-version": process.version,
        "x-bitfab-install-id": getOrCreateInstallId(),
    };
}
/**
 * Canonical header set for an authenticated JSON POST from a Bitfab plugin
 * to the Bitfab server: `Content-Type`, `Authorization`, and the full
 * identity header set from {@link buildBitfabClientHeaders}. Callers may
 * spread additional transport headers (e.g. `Accept` for SSE) alongside.
 */
export function buildBitfabRequestHeaders(apiKey, pluginVersion, platform) {
    return {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`,
        ...buildBitfabClientHeaders(pluginVersion, platform),
    };
}
